import React, { useState } from "react";

// Ícono de usuario (SVG)
const UserIcon = () => (
  <svg
    style={{ width: "60px", height: "60px", fill: "#333" }}
    viewBox="0 0 24 24"
  >
    <path d="M12 12c2.76 0 5-2.24 5-5s-2.24-5-5-5-5 2.24-5 5 2.24 5 5 5zm0 2c-3.33 0-10 1.67-10 5v3h20v-3c0-3.33-6.67-5-10-5z" />
  </svg>
);

const InicioSesion = ({ onLogin, onClose }) => {
  const [usuario, setUsuario] = useState("");
  const [contrasena, setContrasena] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!usuario || !contrasena) {
      alert("Por favor, rellena todos los campos");
      return;
    }
    if (onLogin) {
      onLogin({ usuario, contrasena });
    } else {
      console.log({ usuario, contrasena });
    }
  };

  // Estilo para cubrir toda la pantalla y centrar el modal
  const estilosOverlay = {
    position: "fixed",
    top: 0,
    left: 0,
    width: "100vw",
    height: "100vh",
    backgroundColor: "rgba(0,0,0,0.5)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "'Arial', sans-serif",
    zIndex: 9999
  };

  // Estilo del recuadro modal principal (fondo beige)
  const estilosModal = {
    position: "relative",
    backgroundColor: "#F5F5DC", // Beige
    borderRadius: "15px", // Bordes redondeados
    padding: "40px 20px 20px 20px",
    width: "300px",
    textAlign: "center"
  };

  // Botón "X" para cerrar el modal
  const estilosCerrar = {
    position: "absolute",
    top: "10px",
    right: "10px",
    background: "none",
    border: "none",
    fontSize: "18px",
    cursor: "pointer",
    color: "#333"
  };

  // Estilo del título "Inicio de Sesión"
  const estilosTitulo = {
    margin: "20px 0",
    fontSize: "20px",
    fontWeight: "bold",
    color: "#333"
  };

  // Estilos de los inputs: sin borde ni fondo
  const estilosInput = {
    width: "100%",
    padding: "10px 5px",
    margin: "10px 0",
    fontSize: "16px",
    outline: "none",
    border: "none",
    background: "none",
    color: "#333"
  };

  // Estilo del botón "Enviar": sin fondo ni borde
  const estilosBoton = {
    width: "100%",
    padding: "10px",
    marginTop: "20px",
    fontSize: "16px",
    cursor: "pointer",
    outline: "none",
    border: "none",
    background: "none",
    color: "#333"
  };

  return (
    <div style={estilosOverlay}>
      <div style={estilosModal}>
        {onClose && (
          <button style={estilosCerrar} onClick={onClose}>
            X
          </button>
        )}
        {/* Ícono de persona encima del recuadro */}
        <div style={{ marginTop: "-40px" }}>
          <UserIcon />
        </div>
        <div style={estilosTitulo}>Inicio de Sesión</div>
        <form onSubmit={handleSubmit}>
          <input
            type="text"
            placeholder="Usuario"
            style={estilosInput}
            value={usuario}
            onChange={(e) => setUsuario(e.target.value)}
          />
          <input
            type="password"
            placeholder="Contraseña"
            style={estilosInput}
            value={contrasena}
            onChange={(e) => setContrasena(e.target.value)}
          />
          <button type="submit" style={estilosBoton}>
            Enviar
          </button>
        </form>
      </div>
    </div>
  );
};

export default InicioSesion;
